import urllib.request, urllib.error
base = 'http://localhost:5000'
words = ['admin','login','logout','panel','dashboard','upload','download','about','contact','docs','test','dev','debug','cgi','console','root','mgmt','manager','__debug__','__admin__','secret','secrets','config','configs','settings','setup','tools','shell','cmd','run','exec','execute','source','src','static','assets','public','private','hidden','data','db','database','dump','backup','backups','old','v1','v2','api','api/v1','api/v2','health','healthz','metrics','status','version','info','home','index','flag','flags','key','keys','token','tokens','.env','.git','git','githead','server','app','application','main','ping','robots.txt','sitemap.xml','favicon.ico']
paths = []
for w in words:
    paths.append('/'+w)
    paths.append('/'+w+'/')

for p in paths:
    url = base + p
    try:
        with urllib.request.urlopen(url, timeout=2) as resp:
            body = resp.read(200)
