from xml.etree import ElementTree as ET
samples = [
    '<?xml version="1.0"?><Book><Title>T</Title></Book>',
    '<?xml version="1.0"?><!DOCTYPE foo [ <!ENTITY test "hello"> ]><Book><Title>&test;</Title></Book>',
    '<?xml version="1.0"?><!DOCTYPE foo SYSTEM "http://example.com/evil.dtd"><Book><Title>T</Title></Book>',
]
for i,s in enumerate(samples,1):
    try:
        r = ET.fromstring(s)
        print(i, 'OK', r.tag)
    except Exception as e:
        print(i, 'ERR', type(e).__name__, str(e)[:80])

